import datetime
import http.client
import json
import logging
import ssl
import urllib.error
import urllib.parse
import urllib.request
from decimal import Decimal

import fabric.functions as fn

udf = fn.UserDataFunctions()

PARIS_TZ = datetime.timezone(datetime.timedelta(hours=1))
GREENLUCK_BASE = "https://pre-161o-sp.sbx.bet/cache/161/fr/li"
GREENLUCK_HIDENSEEK = "8ce92afecb8a002f7471da5a79231725cddaf6a9"
DEFAULT_GREENLUCK_SPORT_IDS = ["14", "15", "16", "17", "27", "28", "29", "31", "32"]
GREENLUCK_HEADERS = {
    "accept": "application/json, */*",
    "accept-language": "fr-FR,fr;q=0.9,en-US;q=0.8,en;q=0.7",
    "accept-encoding": "gzip, deflate, br",
    "cache-control": "no-cache",
    "origin": "https://greenluck.com",
    "pragma": "no-cache",
    "referer": "https://greenluck.com/",
    "user-agent": (
        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 "
        "(KHTML, like Gecko) Chrome/149.0.0.0 Safari/537.36"
    ),
}
SLOTT_API_URL = "https://slott-france.com/api-2/betline/events/all"
SLOTT_QUERY = {
    "ctag": "fr-FR",
    "hideClosed": "true",
    "flags": "reg,urlv2,orn2,mm2,rrc,nodup,cmg",
}

WRITE_COLUMNS = [
    "source_insertion", "date_pari", "id_bookmaker", "id_sport",
    "libelle_competition", "libelle_evenement", "id_type_pari",
    "cote_bookmaker", "mise_engagee", "id_resultat",
    "cote_marche_reference", "cote_vraie_mpto", "probabilite_implicite",
    "probabilite_reelle_mpto", "trj_bookmaker", "trj_ps3838", "trj_marche",
    "pourcentage_boost", "critere_kelly", "flag_surebet", "date_heure_maj_scrap",
]


def _serialize(value):
    if isinstance(value, (datetime.datetime, datetime.date)):
        return value.isoformat()
    if isinstance(value, Decimal):
        return float(value)
    if isinstance(value, bytes):
        return value.decode("utf-8")
    return value


def _row_to_dict(cursor, row):
    cols = [col[0] for col in cursor.description]
    return {cols[i]: _serialize(row[i]) for i in range(len(cols))}


def _query_table(cursor, sql):
    cursor.execute(sql)
    rows = cursor.fetchall()
    if not rows:
        return []
    return [_row_to_dict(cursor, row) for row in rows]


def _insert_payload(input_data):
    payload = {
        "source_insertion": input_data.get("source_insertion") or "Manuel",
        "date_pari": input_data.get("date_pari"),
        "id_bookmaker": input_data.get("id_bookmaker"),
        "id_sport": input_data.get("id_sport"),
        "libelle_evenement": input_data.get("libelle_evenement"),
        "id_type_pari": input_data.get("id_type_pari"),
        "cote_bookmaker": input_data.get("cote_bookmaker"),
        "mise_engagee": input_data.get("mise_engagee"),
        "id_resultat": input_data.get("id_resultat"),
        "flag_surebet": input_data.get("flag_surebet") or False,
    }
    for key in [
        "libelle_competition", "cote_marche_reference", "cote_vraie_mpto",
        "probabilite_implicite", "probabilite_reelle_mpto", "trj_bookmaker",
        "trj_ps3838", "trj_marche", "pourcentage_boost", "critere_kelly",
        "date_heure_maj_scrap",
    ]:
        val = input_data.get(key)
        if val is not None:
            payload[key] = val
    cote = payload.get("cote_bookmaker")
    if cote and payload.get("probabilite_implicite") is None:
        try:
            payload["probabilite_implicite"] = 1.0 / float(cote)
        except (TypeError, ZeroDivisionError):
            pass
    return {k: v for k, v in payload.items() if v is not None}


def _normalize_sport_ids(sport_ids):
    if sport_ids is None or sport_ids == "":
        return list(DEFAULT_GREENLUCK_SPORT_IDS)
    if isinstance(sport_ids, str):
        try:
            parsed = json.loads(sport_ids)
        except (json.JSONDecodeError, TypeError, ValueError):
            return [str(sport_ids)]
        if isinstance(parsed, list):
            ids = [str(x) for x in parsed]
        else:
            ids = [str(parsed)]
    elif isinstance(sport_ids, list):
        ids = [str(x) for x in sport_ids]
    else:
        ids = [str(sport_ids)]
    if not ids:
        return list(DEFAULT_GREENLUCK_SPORT_IDS)
    return ids


def _fetch_greenluck_json(path):
    url = GREENLUCK_BASE + path
    parsed = urllib.parse.urlparse(url)
    host = parsed.hostname
    req_path = parsed.path
    if parsed.query:
        req_path = req_path + "?" + parsed.query

    conn = http.client.HTTPSConnection(
        host,
        context=ssl.create_default_context(),
        timeout=45,
    )
    conn.request(
        "GET",
        req_path,
        headers={
            "Host": host,
            "User-Agent": GREENLUCK_HEADERS["user-agent"],
            "Accept": GREENLUCK_HEADERS["accept"],
            "Accept-Language": GREENLUCK_HEADERS["accept-language"],
            "Origin": GREENLUCK_HEADERS["origin"],
            "Referer": GREENLUCK_HEADERS["referer"],
            "Connection": "close",
        },
    )
    resp = conn.getresponse()
    raw = resp.read()
    status = resp.status
    hdrs = resp.getheaders()
    conn.close()

    if status >= 400:
        raise fn.UserThrownError("Greenluck HTTP " + str(status) + " " + path)
    return json.loads(raw.decode("utf-8"))


def _parse_greenluck_cutoff(date_raw):
    if not date_raw:
        return None
    normalized = date_raw.replace("Z", "+00:00")
    dt = datetime.datetime.fromisoformat(normalized)
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=datetime.timezone.utc)
    return dt.astimezone(PARIS_TZ)


def _scrape_greenluck_sports(sport_ids, extraction):
    sport_set = set(sport_ids)
    info = _fetch_greenluck_json("/Europe-Paris/sports-info.json")
    tournaments = {}
    for tid, t in (info.get("tournaments") or {}).items():
        if str(t.get("sportId")) in sport_set:
            tournaments[tid] = t
    rows = []

    for tid, tournament in tournaments.items():
        if tournament.get("hasOutright"):
            continue
        try:
            prematch_path = (
                "/" + str(tid) + "/prematch-by-tournaments.json?hidenseek=" + GREENLUCK_HIDENSEEK
            )
            data = _fetch_greenluck_json(prematch_path)
        except fn.UserThrownError:
            continue

        for event in data.get("events") or []:
            main_odds = (event.get("main_odds") or {}).get("main") or {}
            if len(main_odds) != 2:
                continue

            sorted_odds = sorted(main_odds.values(), key=lambda o: o.get("team_side") or 0)
            cutoff = _parse_greenluck_cutoff(event.get("date_start"))
            competition = event.get("tournament_name") or tournament.get("name") or ""
            nom1 = (sorted_odds[0].get("team_name") or "").strip()
            nom2 = (sorted_odds[1].get("team_name") or "").strip()
            evenement = nom1 + " vs " + nom2

            for odd in sorted_odds:
                competiteur = (odd.get("team_name") or "").strip()
                cote = odd.get("odd_value")
                if cote is None:
                    continue
                if competiteur.lower() in ("oui", "non"):
                    continue
                rows.append(
                    {
                        "bookmaker": "Greenluck",
                        "competition": competition,
                        "evenement": evenement,
                        "competiteur": competiteur,
                        "cote": float(cote),
                        "cutoff": cutoff.isoformat() if cutoff else None,
                        "extraction": extraction.isoformat(),
                    }
                )

    return rows


def _normalize_region_ids(region_ids):
    if region_ids is None:
        return ["1970324836974625"]
    if isinstance(region_ids, str):
        parsed = json.loads(region_ids)
        if isinstance(parsed, list):
            return [str(x) for x in parsed]
        return [str(parsed)]
    if isinstance(region_ids, list):
        return [str(x) for x in region_ids]
    return [str(region_ids)]


def _fetch_slott_events(region_id):
    params = dict(SLOTT_QUERY)
    params["region_id"] = region_id
    url = SLOTT_API_URL + "?" + urllib.parse.urlencode(params)
    req = urllib.request.Request(
        url,
        headers={
            "Accept": "application/json",
            "User-Agent": "Mozilla/5.0 (compatible; ScrappingBet/1.0)",
        },
    )
    try:
        with urllib.request.urlopen(req, timeout=45) as resp:
            return json.loads(resp.read().decode("utf-8"))
    except urllib.error.HTTPError as exc:
        raise fn.UserThrownError("Slott HTTP " + str(exc.code))
    except urllib.error.URLError as exc:
        raise fn.UserThrownError("Slott reseau: " + str(exc.reason))


def _scrape_slott_region(region_id, extraction):
    data = _fetch_slott_events(region_id)
    events = data.get("events") or []
    rows = []
    league_cache = {}

    for event in events:
        league = event.get("league") or {}
        league_id = league.get("id")
        if league.get("name") and league_id is not None:
            league_cache[league_id] = league
        full_league = league_cache.get(league_id, league)
        competition = full_league.get("name")

        if len(event.get("competitors") or []) != 2:
            continue

        market = None
        for m in (event.get("markets") or []):
            if m.get("primary"):
                market = m
                break
        if market is None:
            for m in (event.get("markets") or []):
                if len(m.get("runners") or []) == 2:
                    market = m
                    break
        if market is None:
            continue

        runners = market.get("runners") or []
        if len(runners) != 2:
            continue

        competitors = {}
        for c in (event.get("competitors") or []):
            if c.get("homeAway"):
                competitors[c.get("homeAway")] = c.get("name")

        kickoff_raw = event.get("kickoff")
        cutoff = None
        if kickoff_raw:
            cutoff = datetime.datetime.fromtimestamp(
                kickoff_raw / 1000,
                tz=datetime.timezone.utc,
            ).astimezone(PARIS_TZ)

        for runner in runners:
            tags = runner.get("tags") or []
            tag = tags[0] if tags else None
            competiteur = competitors.get(tag, runner.get("name"))
            cote = runner.get("price")
            if cote is None:
                continue
            rows.append(
                {
                    "bookmaker": "Slott",
                    "competition": competition,
                    "evenement": event.get("name"),
                    "competiteur": competiteur,
                    "cote": float(cote),
                    "cutoff": cutoff.isoformat() if cutoff else None,
                    "extraction": extraction.isoformat(),
                }
            )

    filtered = []
    for r in rows:
        comp = (r.get("competiteur") or "").lower()
        if comp not in ("oui", "non"):
            filtered.append(r)
    return filtered


@udf.function()
def scrapeGreenluck(sportIds):
    logging.info("scrapeGreenluck")
    ids = _normalize_sport_ids(sportIds)
    extraction = datetime.datetime.now(PARIS_TZ)
    rows = _scrape_greenluck_sports(ids, extraction)
    return json.dumps(rows)


@udf.function()
def fetchGreenluckJson(path):
    logging.info("fetchGreenluckJson")
    if not path.startswith("/"):
        path = "/" + path
    return json.dumps(_fetch_greenluck_json(path))


@udf.function()
def scrapeSlott(region_ids):
    logging.info("scrapeSlott")
    ids = _normalize_region_ids(region_ids)
    extraction = datetime.datetime.now(PARIS_TZ)
    all_rows = []
    for region_id in ids:
        all_rows.extend(_scrape_slott_region(region_id, extraction))
    return json.dumps(all_rows)


@udf.function()
def fetchSlottBetline(region_id):
    logging.info("fetchSlottBetline")
    data = _fetch_slott_events(region_id)
    return json.dumps(data)


@udf.connection(argName="scrappingbet", alias="scrappingbet")
@udf.function()
def listDimensions(scrappingbet):
    logging.info("listDimensions called")
    conn = scrappingbet.connect()
    cursor = conn.cursor()
    try:
        bookmakers = _query_table(cursor, "SELECT id_bookmaker, nom, type_bookmaker FROM dbo.dim_bookmaker WHERE actif = 1 ORDER BY id_bookmaker")
        sports = _query_table(cursor, "SELECT id_sport, nom, type_sport FROM dbo.dim_sport WHERE actif = 1 ORDER BY id_sport")
        types_pari = _query_table(cursor, "SELECT id_type_pari, libelle FROM dbo.dim_type_pari WHERE actif = 1 ORDER BY id_type_pari")
        resultats = _query_table(cursor, "SELECT id_resultat, libelle FROM dbo.dim_resultat WHERE actif = 1 ORDER BY id_resultat")
        result = {
            "bookmakers": [{"id": int(r["id_bookmaker"]), "nom": str(r["nom"]), "typeBookmaker": str(r.get("type_bookmaker") or "--")} for r in bookmakers],
            "sports": [{"id": int(r["id_sport"]), "nom": str(r["nom"]), "typeSport": str(r.get("type_sport") or "--")} for r in sports],
            "typesPari": [{"id": int(r["id_type_pari"]), "libelle": str(r["libelle"])} for r in types_pari],
            "resultats": [{"id": int(r["id_resultat"]), "libelle": str(r["libelle"])} for r in resultats],
        }
        return json.dumps(result)
    finally:
        cursor.close()
        conn.close()


@udf.connection(argName="scrappingbet", alias="scrappingbet")
@udf.function()
def createFaitPari(scrappingbet, data):
    payload = _insert_payload(json.loads(data))
    conn = scrappingbet.connect()
    cursor = conn.cursor()
    try:
        cols = [c for c in WRITE_COLUMNS if c in payload]
        placeholders = ", ".join(["?"] * len(cols))
        sql = "INSERT INTO dbo.fait_paris (" + ", ".join(cols) + ") OUTPUT INSERTED.* VALUES (" + placeholders + ")"
        cursor.execute(sql, [payload[c] for c in cols])
        row = cursor.fetchone()
        if row is None:
            raise fn.UserThrownError("Insert sans ligne retournee.")
        result = _row_to_dict(cursor, row)
        conn.commit()
        return json.dumps(result)
    finally:
        cursor.close()
        conn.close()


@udf.connection(argName="scrappingbet", alias="scrappingbet")
@udf.function()
def updateFaitPari(scrappingbet, idPari, patch):
    patch_data = json.loads(patch)
    conn = scrappingbet.connect()
    cursor = conn.cursor()
    try:
        sets = []
        values = []
        for key in WRITE_COLUMNS:
            if key in patch_data:
                sets.append(key + " = ?")
                values.append(patch_data[key])
        if not sets:
            raise fn.UserThrownError("Aucun champ a mettre a jour.")
        sql = "UPDATE dbo.fait_paris SET " + ", ".join(sets) + " OUTPUT INSERTED.* WHERE id_pari = ?"
        values.append(idPari)
        cursor.execute(sql, values)
        row = cursor.fetchone()
        if row is None:
            raise fn.UserThrownError("Pari " + str(idPari) + " introuvable.")
        result = _row_to_dict(cursor, row)
        conn.commit()
        return json.dumps(result)
    finally:
        cursor.close()
        conn.close()


@udf.connection(argName="scrappingbet", alias="scrappingbet")
@udf.function()
def deleteFaitPari(scrappingbet, idPari):
    conn = scrappingbet.connect()
    cursor = conn.cursor()
    try:
        cursor.execute("DELETE FROM dbo.fait_paris WHERE id_pari = ?", [idPari])
        if cursor.rowcount == 0:
            raise fn.UserThrownError("Pari " + str(idPari) + " introuvable.")
        conn.commit()
        return json.dumps({"ok": True})
    finally:
        cursor.close()
        conn.close()

