def _serialize(value):
    if isinstance(value, (datetime.datetime, datetime.date)):
        return value.isoformat()
    if isinstance(value, Decimal):
        return float(value)
    if isinstance(value, bytes):
        return value.decode("utf-8")
    return value


def _row_to_dict(cursor, row):
    cols = [col[0] for col in cursor.description]
    return {cols[i]: _serialize(row[i]) for i in range(len(cols))}


def _query_table(cursor, sql):
    cursor.execute(sql)
    rows = cursor.fetchall()
    if not rows:
        return []
    return [_row_to_dict(cursor, row) for row in rows]


def _insert_payload(input_data):
    payload = {
        "source_insertion": input_data.get("source_insertion") or "Manuel",
        "date_pari": input_data.get("date_pari"),
        "id_bookmaker": input_data.get("id_bookmaker"),
        "id_sport": input_data.get("id_sport"),
        "libelle_evenement": input_data.get("libelle_evenement"),
        "id_type_pari": input_data.get("id_type_pari"),
        "cote_bookmaker": input_data.get("cote_bookmaker"),
        "mise_engagee": input_data.get("mise_engagee"),
        "id_resultat": input_data.get("id_resultat"),
        "flag_surebet": input_data.get("flag_surebet") or False,
    }
    for key in [
        "libelle_competition", "cote_marche_reference", "cote_vraie_mpto",
        "probabilite_implicite", "probabilite_reelle_mpto", "trj_bookmaker",
        "trj_ps3838", "trj_marche", "pourcentage_boost", "critere_kelly",
        "date_heure_maj_scrap",
    ]:
        val = input_data.get(key)
        if val is not None:
            payload[key] = val
    cote = payload.get("cote_bookmaker")
    if cote and payload.get("probabilite_implicite") is None:
        try:
            payload["probabilite_implicite"] = 1.0 / float(cote)
        except (TypeError, ZeroDivisionError):
            pass
    return {k: v for k, v in payload.items() if v is not None}


def _normalize_sport_ids(sport_ids):
    if sport_ids is None or sport_ids == "":
        return list(DEFAULT_GREENLUCK_SPORT_IDS)
    if isinstance(sport_ids, str):
        try:
            parsed = json.loads(sport_ids)
        except (json.JSONDecodeError, TypeError, ValueError):
            return [str(sport_ids)]
        if isinstance(parsed, list):
            ids = [str(x) for x in parsed]
        else:
            ids = [str(parsed)]
    elif isinstance(sport_ids, list):
        ids = [str(x) for x in sport_ids]
    else:
        ids = [str(sport_ids)]
    if not ids:
        return list(DEFAULT_GREENLUCK_SPORT_IDS)
    return ids


def _fetch_greenluck_json(path):
    url = GREENLUCK_BASE + path
    parsed = urllib.parse.urlparse(url)
    host = parsed.hostname
    req_path = parsed.path
    if parsed.query:
        req_path = req_path + "?" + parsed.query

    conn = http.client.HTTPSConnection(
        host,
        context=ssl.create_default_context(),
        timeout=45,
    )
    conn.request(
        "GET",
        req_path,
        headers={
            "Host": host,
            "User-Agent": GREENLUCK_HEADERS["user-agent"],
            "Accept": GREENLUCK_HEADERS["accept"],
            "Accept-Language": GREENLUCK_HEADERS["accept-language"],
            "Origin": GREENLUCK_HEADERS["origin"],
            "Referer": GREENLUCK_HEADERS["referer"],
            "Connection": "close",
        },
    )
    resp = conn.getresponse()
    raw = resp.read()
    status = resp.status
    hdrs = resp.getheaders()
    conn.close()

    if status >= 400:
        raise fn.UserThrownError("Greenluck HTTP " + str(status) + " " + path)
    return json.loads(raw.decode("utf-8"))


