    dt = datetime.datetime.fromisoformat(normalized)
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=datetime.timezone.utc)
    return dt.astimezone(PARIS_TZ)


def _scrape_greenluck_sports(sport_ids, extraction):
    sport_set = set(sport_ids)
    info = _fetch_greenluck_json("/Europe-Paris/sports-info.json")
    tournaments = {}
    for tid, t in (info.get("tournaments") or {}).items():
        if str(t.get("sportId")) in sport_set:
            tournaments[tid] = t
    rows = []

    for tid, tournament in tournaments.items():
        if tournament.get("hasOutright"):
            continue
        try:
            prematch_path = (
                "/" + str(tid) + "/prematch-by-tournaments.json?hidenseek=" + GREENLUCK_HIDENSEEK
            )
            data = _fetch_greenluck_json(prematch_path)
        except fn.UserThrownError:
            continue

        for event in data.get("events") or []:
            main_odds = (event.get("main_odds") or {}).get("main") or {}
            if len(main_odds) != 2:
                continue

            sorted_odds = sorted(main_odds.values(), key=lambda o: o.get("team_side") or 0)
            cutoff = _parse_greenluck_cutoff(event.get("date_start"))
            competition = event.get("tournament_name") or tournament.get("name") or ""
            nom1 = (sorted_odds[0].get("team_name") or "").strip()
            nom2 = (sorted_odds[1].get("team_name") or "").strip()
            evenement = nom1 + " vs " + nom2

            for odd in sorted_odds:
                competiteur = (odd.get("team_name") or "").strip()
                cote = odd.get("odd_value")
                if cote is None:
                    continue
                if competiteur.lower() in ("oui", "non"):
                    continue
                rows.append(
                    {
                        "bookmaker": "Greenluck",
                        "competition": competition,
                        "evenement": evenement,
                        "competiteur": competiteur,
                        "cote": float(cote),
                        "cutoff": cutoff.isoformat() if cutoff else None,
                        "extraction": extraction.isoformat(),
                    }
                )

    return rows


def _normalize_region_ids(region_ids):
    if region_ids is None:
        return ["1970324836974625"]
    if isinstance(region_ids, str):
        parsed = json.loads(region_ids)
        if isinstance(parsed, list):
            return [str(x) for x in parsed]
        return [str(parsed)]
    if isinstance(region_ids, list):
        return [str(x) for x in region_ids]
    return [str(region_ids)]


def _fetch_slott_events(region_id):
    params = dict(SLOTT_QUERY)
    params["region_id"] = region_id
    url = SLOTT_API_URL + "?" + urllib.parse.urlencode(params)
    req = urllib.request.Request(
        url,
        headers={
            "Accept": "application/json",
            "User-Agent": "Mozilla/5.0 (compatible; ScrappingBet/1.0)",
        },
    )
    try:
        with urllib.request.urlopen(req, timeout=45) as resp:
            return json.loads(resp.read().decode("utf-8"))
    except urllib.error.HTTPError as exc:
        raise fn.UserThrownError("Slott HTTP " + str(exc.code))
    except urllib.error.URLError as exc:
        raise fn.UserThrownError("Slott reseau: " + str(exc.reason))


def _scrape_slott_region(region_id, extraction):
    data = _fetch_slott_events(region_id)
    events = data.get("events") or []
    rows = []
    league_cache = {}

    for event in events:
        league = event.get("league") or {}
        league_id = league.get("id")
        if league.get("name") and league_id is not None:
            league_cache[league_id] = league
        full_league = league_cache.get(league_id, league)
        competition = full_league.get("name")

        if len(event.get("competitors") or []) != 2:
            continue

        market = None
        for m in (event.get("markets") or []):
            if m.get("primary"):
                market = m
                break
        if market is None:
            for m in (event.get("markets") or []):
                if len(m.get("runners") or []) == 2:
                    market = m
                    break
        if market is None:
            continue

        runners = market.get("runners") or []
        if len(runners) != 2:
            continue

        competitors = {}
        for c in (event.get("competitors") or []):
            if c.get("homeAway"):
                competitors[c.get("homeAway")] = c.get("name")

        kickoff_raw = event.get("kickoff")
        cutoff = None
        if kickoff_raw:
            cutoff = datetime.datetime.fromtimestamp(
                kickoff_raw / 1000,
                tz=datetime.timezone.utc,
            ).astimezone(PARIS_TZ)

        for runner in runners:
            tags = runner.get("tags") or []
            tag = tags[0] if tags else None
            competiteur = competitors.get(tag, runner.get("name"))
            cote = runner.get("price")
            if cote is None:
                continue
            rows.append(
                {
                    "bookmaker": "Slott",
                    "competition": competition,
                    "evenement": event.get("name"),
                    "competiteur": competiteur,
                    "cote": float(cote),
                    "cutoff": cutoff.isoformat() if cutoff else None,
                    "extraction": extraction.isoformat(),
                }
            )

    filtered = []
    for r in rows:
        comp = (r.get("competiteur") or "").lower()
        if comp not in ("oui", "non"):
            filtered.append(r)
    return filtered


@udf.function()
def scrapeGreenluck(sportIds):
    logging.info("scrapeGreenluck")
    ids = _normalize_sport_ids(sportIds)
    extraction = datetime.datetime.now(PARIS_TZ)
    rows = _scrape_greenluck_sports(ids, extraction)
    return json.dumps(rows)


@udf.function()
def fetchGreenluckJson(path):
    logging.info("fetchGreenluckJson")
    if not path.startswith("/"):
        path = "/" + path
    return json.dumps(_fetch_greenluck_json(path))


@udf.function()
def scrapeSlott(region_ids):
    logging.info("scrapeSlott")
    ids = _normalize_region_ids(region_ids)
    extraction = datetime.datetime.now(PARIS_TZ)
    all_rows = []
    for region_id in ids:
        all_rows.extend(_scrape_slott_region(region_id, extraction))
    return json.dumps(all_rows)


@udf.function()
def fetchSlottBetline(region_id):
    logging.info("fetchSlottBetline")
    data = _fetch_slott_events(region_id)
    return json.dumps(data)


