@udf.connection(argName="scrappingbet", alias="scrappingbet")
@udf.function()
def createFaitPari(scrappingbet, data):
    payload = _insert_payload(json.loads(data))
    conn = scrappingbet.connect()
    cursor = conn.cursor()
    try:
        cols = [c for c in WRITE_COLUMNS if c in payload]
        placeholders = ", ".join(["?"] * len(cols))
        sql = "INSERT INTO dbo.fait_paris (" + ", ".join(cols) + ") OUTPUT INSERTED.* VALUES (" + placeholders + ")"
        cursor.execute(sql, [payload[c] for c in cols])
        row = cursor.fetchone()
        if row is None:
            raise fn.UserThrownError("Insert sans ligne retournee.")
        result = _row_to_dict(cursor, row)
        conn.commit()
        return json.dumps(result)
    finally:
        cursor.close()
        conn.close()


@udf.connection(argName="scrappingbet", alias="scrappingbet")
@udf.function()
def updateFaitPari(scrappingbet, idPari, patch):
    patch_data = json.loads(patch)
    conn = scrappingbet.connect()
    cursor = conn.cursor()
    try:
        sets = []
        values = []
        for key in WRITE_COLUMNS:
            if key in patch_data:
                sets.append(key + " = ?")
                values.append(patch_data[key])
        if not sets:
            raise fn.UserThrownError("Aucun champ a mettre a jour.")
        sql = "UPDATE dbo.fait_paris SET " + ", ".join(sets) + " OUTPUT INSERTED.* WHERE id_pari = ?"
        values.append(idPari)
        cursor.execute(sql, values)
        row = cursor.fetchone()
        if row is None:
            raise fn.UserThrownError("Pari " + str(idPari) + " introuvable.")
        result = _row_to_dict(cursor, row)
        conn.commit()
        return json.dumps(result)
    finally:
        cursor.close()
        conn.close()


@udf.connection(argName="scrappingbet", alias="scrappingbet")
@udf.function()
def deleteFaitPari(scrappingbet, idPari):
    conn = scrappingbet.connect()
    cursor = conn.cursor()
    try:
        cursor.execute("DELETE FROM dbo.fait_paris WHERE id_pari = ?", [idPari])
        if cursor.rowcount == 0:
            raise fn.UserThrownError("Pari " + str(idPari) + " introuvable.")
        conn.commit()
        return json.dumps({"ok": True})
    finally:
        cursor.close()
        conn.close()
